export function useAgents(
  limit = 50,
  offset = 0,
  filters?: AgentsFilters,
) {
  const { api } = useObservabilityContext()
  const [agents, setAgents] = useState<AgentRow[]>([])
  const [meta, setMeta] = useState<PlivoMeta>({
    limit,
