// Agent framework — what the agent under test is built with.
const FRAMEWORK_OPTIONS = [
  { label: 'LiveKit', value: 'livekit' },
  { label: 'Pipecat', value: 'pipecat' },
]

// Testing framework — what ran the eval suite.
const TESTING_FRAMEWORK_OPTIONS = [
  { label: 'pytest', value: 'pytest' },
  { label: 'Vitest', value: 'vitest' },
]

function PassRateBar({ passed, total }: { passed: number; total: number }) {
  const pct = total > 0 ? Math.round((passed / total) * 100) : 0
  return (
    <div className="flex items-center gap-2 min-w-[120px]">
      <span className="font-mono text-xs-600 tabular-nums w-10">{pct}%</span>
      <div className="flex-1 h-1.5 rounded-full bg-muted overflow-hidden max-w-[90px]">
        <div className="h-full bg-foreground" style={{ width: `${pct}%` }} />
      </div>
    </div>
  )
}

function FrameworkPill({
  name,
  version,
  icon: Icon,
}: {
  name: string | null
  version: string | null
  icon: LucideIcon
}) {
  if (!name) return <span className="text-muted-foreground">—</span>
  return (
    <span className={cn(
      'inline-flex shrink-0 items-center gap-1.5 px-2 py-0.5 rounded-full bg-muted border text-xs-500 whitespace-nowrap',
    )}>
      <Icon className="h-3 w-3 shrink-0 text-muted-foreground" />
      {name}
      {version && <span className="text-muted-foreground font-mono text-[11px]">{version}</span>}
    </span>
  )
}

function FrameworkBadge({ name, version }: { name: string | null; version: string | null }) {
  return <FrameworkPill name={name} version={version} icon={Bot} />
}

function TestingFrameworkBadge({ name, version }: { name: string; version: string | null }) {
  return <FrameworkPill name={name} version={version} icon={FlaskConical} />
}

function formatTokens(tokens: number): string {
  return tokens > 0 ? tokens.toLocaleString() : '—'
}

function formatCost(cost: number | null): string {
  return cost == null ? '—' : `$${cost.toFixed(cost < 0.01 ? 4 : 2)}`
}

export const EvalsPage = ({
  onRunClick,
  agentId: agentIdProp,
}: {
  onRunClick?: (runId: string) => void
  /** When set, locks the list to this agent — overrides the URL-synced
   * `agent_id` filter so the page can be embedded inside the agent
   * detail dashboard. */
  agentId?: string
}) => {
  // URL-synced filter state — written by the DataTable toolbar via `useDataTable`.
  // Column ids below (`agent_id`, `account_id`, `framework`, `started_at`) become the URL keys.
  const [page] = useQueryState('page', parseAsInteger.withDefault(1))
  const [perPage] = useQueryState('perPage', parseAsInteger.withDefault(10))
  const [agentIdQuery] = useQueryState('agent_id', parseAsString.withDefault(''))
  // Prop wins so the embedded-in-agent-dashboard case is forced; falls
  // back to URL-synced filter on the standalone cross-agent route.
  const agentId = agentIdProp ?? agentIdQuery
  const [accountId] = useQueryState('account_id', parseAsString.withDefault(''))
  const [framework] = useQueryState(
    'framework',
    parseAsArrayOf(parseAsString, ',').withDefault([]),
  )
  const [testingFramework] = useQueryState(
    'testing_framework',
    parseAsArrayOf(parseAsString, ',').withDefault([]),
  )
  // Single-date filter emits the picked day's midnight (local) as an epoch-ms
  // string. Expanded server-side into a 00:00 → next-midnight window.
  const [startedAt] = useQueryState(
    'started_at',
    parseAsArrayOf(parseAsString, ',').withDefault([]),
  )
  const startedDay = useMemo(() => {
    const v = startedAt[0]
    if (!v) return undefined
    const d = new Date(Number(v))
    return Number.isNaN(d.getTime()) ? undefined : d
  }, [startedAt])
  const startedFromIso = useMemo(() => startedDay?.toISOString(), [startedDay])
  const startedToIso = useMemo(() => {
    if (!startedDay) return undefined
    const end = new Date(startedDay)
    end.setHours(23, 59, 59, 999)
    return end.toISOString()
  }, [startedDay])

  const { runs, meta, loading, error, refetch } = useEvalRuns(
    perPage,
    (page - 1) * perPage,
    {
      agentId: agentId || undefined,
      accountId: accountId || undefined,
      framework: framework.length ? framework : undefined,
      testingFramework: testingFramework.length ? testingFramework : undefined,
      startedFrom: startedFromIso,
      startedTo: startedToIso,
    },
  )

  const hasRunningRun = runs.some((run) => run.status === 'running')
  useEffect(() => {
    if (!hasRunningRun) return
    const id = window.setInterval(() => refetch(), 1500)
    return () => window.clearInterval(id)
  }, [hasRunningRun, refetch])

  const columns = useMemo<ColumnDef<EvalRunRow>[]>(
    () => [
      {
        id: 'select',
        header: ({ table }) => (
          <Checkbox
            aria-label="Select all rows on this page"
            checked={
              table.getIsAllPageRowsSelected()
                ? true
                : table.getIsSomePageRowsSelected()
                  ? 'indeterminate'
                  : false
            }
            onCheckedChange={(value) => table.toggleAllPageRowsSelected(!!value)}
            onClick={(e) => e.stopPropagation()}
          />
        ),
        cell: ({ row }) => (
          <Checkbox
            aria-label={`Select run ${row.original.run_id}`}
            checked={row.getIsSelected()}
            onCheckedChange={(value) => row.toggleSelected(!!value)}
            onClick={(e) => e.stopPropagation()}
          />
        ),
        enableSorting: false,
        enableHiding: false,
        size: 32,
      },
      {
        id: 'run_id',
        accessorKey: 'run_id',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Run" />,
        cell: ({ row }) =>
          row.original.name ? (
            <span className="font-medium">{row.original.name}</span>
          ) : (
            <span className="font-mono">{row.original.run_id.slice(0, 8)}</span>
          ),
        enableSorting: false,
        meta: { label: 'Run' },
      },
      {
        // Agent identity. Primary line is the human name when present,
        // falling back to the opaque id. The id appears as small
        // secondary text whenever a name is shown so deep-links remain
        // discoverable.
        id: 'agent_id',
        accessorKey: 'agent_id',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Agent" />,
        cell: ({ row }) => {
          const id = row.original.agent_id
          const name = row.original.agent_name
          if (!id && !name) return <span className="muted">—</span>
          return (
            <div className="flex flex-col leading-tight">
              <span style={{ font: 'var(--text-p-500)' }}>{name || id}</span>
              {name && id && (
                <span className="text-muted-foreground text-[11px] font-mono">{id}</span>
              )}
            </div>
          )
        },
        enableSorting: false,
      },
      {
        id: 'framework',
        accessorKey: 'framework',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Framework" />,
        cell: ({ row }) => (
          <FrameworkBadge
            name={row.original.framework}
            version={row.original.framework_version}
          />
        ),
        enableSorting: false,
        enableColumnFilter: true,
        meta: {
          label: 'Framework',
          variant: 'multiSelect',
          options: FRAMEWORK_OPTIONS,
        },
      },
      {
        id: 'testing_framework',
        accessorKey: 'testing_framework',
        header: ({ column }) => (
          <DataTableColumnHeader column={column} label="Testing Framework" />
        ),
        cell: ({ row }) => (
          <TestingFrameworkBadge
            name={row.original.testing_framework}
            version={row.original.testing_framework_version}
          />
        ),
        enableSorting: false,
        enableColumnFilter: true,
        meta: {
          label: 'Testing Framework',
          variant: 'multiSelect',
          options: TESTING_FRAMEWORK_OPTIONS,
        },
      },
      {
        id: 'account_id',
        accessorKey: 'account_id',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Account" />,
        cell: ({ row }) =>
          row.original.account_id ? (
            <span className="muted" style={{ fontFamily: 'var(--mono)', fontSize: 12 }}>
              {row.original.account_id}
            </span>
          ) : (
            <span className="muted">—</span>
          ),
        enableSorting: false,
        enableColumnFilter: true,
        meta: { label: 'Account', placeholder: 'Filter by account', variant: 'text' },
      },
      {
        id: 'pass_rate',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Pass rate" />,
        cell: ({ row }) => {
          const r = row.original
          const failed = r.failed + r.errored
          return (
            <div className="flex items-center gap-2">
              <PassRateBar passed={r.passed} total={r.total} />
              {failed > 0 && (
                <Badge
                  variant="outline"
                  className="capitalize border-destructive-border bg-destructive-bg text-destructive"
                >
                  {failed} fail
                </Badge>
              )}
            </div>
          )
        },
        enableSorting: false,
      },
      {
        id: 'total',
        accessorKey: 'total',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Cases" />,
        cell: ({ row }) => <span className="tnum">{row.original.total}</span>,
        enableSorting: false,
        meta: { label: 'Cases' },
      },
      {
        id: 'duration_ms',
        accessorKey: 'duration_ms',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Duration" />,
        cell: ({ row }) => (
          <span className="font-mono tabular-nums">{formatDuration(row.original.duration_ms)}</span>
        ),
        enableSorting: false,
        meta: { label: 'Duration' },
      },
      {
        id: 'total_tokens',
        accessorKey: 'total_tokens',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Tokens" />,
        cell: ({ row }) => <span className="font-mono tabular-nums">{formatTokens(row.original.total_tokens)}</span>,
        enableSorting: false,
        meta: { label: 'Tokens' },
      },
      {
        id: 'estimated_cost_usd',
        accessorKey: 'estimated_cost_usd',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Est. cost" />,
        cell: ({ row }) => <span className="font-mono tabular-nums">{formatCost(row.original.estimated_cost_usd)}</span>,
        enableSorting: false,
        meta: { label: 'Est. cost' },
      },
      {
        id: 'started_at',
        accessorKey: 'started_at',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Started" />,
        cell: ({ row }) => (
          <span className="inline-flex items-center gap-2 tnum" style={{ color: 'var(--ink-2)' }}>
            {row.original.status === 'running' && <span className="inline-block h-2 w-2 rounded-full bg-emerald-500 animate-pulse" />}
            {formatDate(row.original.started_at)}
          </span>
        ),
        enableSorting: false,
        enableColumnFilter: true,
        meta: { label: 'Started', variant: 'date' },
      },
    ],
    [],
  )

  const totalCount = meta.total_count
  const pageCount = Math.max(1, Math.ceil(totalCount / perPage))

  const { table } = useDataTable({
    data: runs,
    columns,
    pageCount,
    initialState: { pagination: { pageIndex: 0, pageSize: 10 } },
    getRowId: (row) => row.run_id,
  })

  const { api } = useObservabilityContext()
  const [confirmOpen, setConfirmOpen] = useState(false)
  const [deleting, setDeleting] = useState(false)
  const [deleteError, setDeleteError] = useState<string | null>(null)
  const selectedIds = Object.keys(table.getState().rowSelection)
  const selectedCount = selectedIds.length

  const handleDelete = async () => {
    setDeleting(true)
    setDeleteError(null)
    try {
      await api.deleteEvalRuns(selectedIds)
      table.resetRowSelection()
      refetch()
      setConfirmOpen(false)
    } catch (e) {
      setDeleteError((e as Error).message)
    } finally {
      setDeleting(false)
    }
  }

  return (
    <div className="w-full p-6 flex flex-col gap-4 min-w-0">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-h2-600 font-semibold m-0">Evals</h1>
          <div className="text-s-400 text-muted-foreground">Test runs across your agents.</div>
        </div>
        <div className="flex items-center gap-2">
          {selectedCount > 0 && (
            <Button
              variant="outline"
              size="sm"
              className="text-destructive [&_svg]:text-current hover:[&_svg]:text-current border-destructive-border hover:bg-destructive-bg"
              onClick={() => setConfirmOpen(true)}
            >
              <Trash2 /> Delete
            </Button>
          )}
          <div className="text-s-400 text-muted-foreground">
            <b className="text-foreground">{totalCount}</b> total
          </div>
        </div>
      </div>

      {error && (
        <div
          role="alert"
          className="border border-border bg-muted text-foreground px-4 py-2.5 rounded-lg text-s-400"
        >
          Failed to load eval runs: {error}
        </div>
      )}

      <ObsDataTable
        table={table}
        toolbar={<DataTableToolbar table={table} />}
        onRowClick={(row) => onRunClick?.(row.original.run_id)}
        totalRowCount={totalCount}
        loading={loading}
      />

      <Dialog open={confirmOpen} onOpenChange={(open) => !deleting && setConfirmOpen(open)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Delete {selectedCount} eval run{selectedCount === 1 ? '' : 's'}?</DialogTitle>
            <DialogDescription>
              This permanently removes the selected run{selectedCount === 1 ? '' : 's'} and every
              case, event, and judgment captured under {selectedCount === 1 ? 'it' : 'them'}. This cannot be undone.
            </DialogDescription>
          </DialogHeader>
          {deleteError && (
            <div className="text-s-400 text-destructive">
              Failed to delete: {deleteError}
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setConfirmOpen(false)} disabled={deleting}>
              Cancel
            </Button>
            <Button
              variant="outline"
              className="text-destructive border-destructive-border hover:bg-destructive-bg"
              onClick={handleDelete}
              disabled={deleting}
            >
              {deleting ? 'Deleting…' : `Delete ${selectedCount}`}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}
